
SELECT veznev, kernev, fizu, fizu * 1.05 AS uj_fizu FROM alkalmazottak ORDER BY veznev;
	--Ez az uj-Fizu oszlop csak a találatokra vonazkozik. Nincs a táblában.
SELECT * FROM alkalmazottak ORDER BY veznev, kernev DESC;
	--DESC: megfordítja a rendezés sorrendjét (csökkenő szám/z-->a)
SELECT allas_id, fizu FROM alkalmazottak ORDER BY allas_id, fizu DESC;

SELECT DISTINCT telefon FROM alkalmazottak ORDER BY telefon;
	--DISTINCT: elveti a duplikátumokat. EGy érték csak egyszer szerepelhet.
SELECT DISTINCT fizu FROM alkalmazottak ORDER BY fizu DESC LIMIT 0, 1;
	--LIMIT x,y: csak az x. indextől számított első y találat jelenjen meg. 
SELECT * FROM alkalmazottak WHERE fizu = (SELECT DISTINCT fizu FROM 
    alkalmazottak ORDER BY fizu DESC LIMIT 0, 1);
    --Itt maga az al-Select eredménye a szűrőfeltétel
SELECT * FROM alkalmazottak WHERE felvetel >= '1999-01-01' ORDER BY felvetel DESC;

SELECT * FROM alkalmazottak WHERE reszleg_id <> 8 ORDER BY veznev, kernev;

SELECT * FROM alkalmazottak WHERE reszleg_id <> 8 AND reszleg_id <> 10;
SELECT * FROM alkalmazottak WHERE NOT reszleg_id IN (8,10);

SELECT * FROM alkalmazottak WHERE fizu > 10000 
	and reszleg_id = 8 ORDER BY fizu DESC;

SELECT * FROM alkalmazottak WHERE fizu > 5000 AND fizu < 7000 ORDER BY fizu;
SELECT * FROM alkalmazottak WHERE fizu BETWEEN 5000 AND 7000 ORDER BY fizu;

SELECT * FROM alkalmazottak WHERE telefon IS NULL;
	-- NULL érték szűrése nem = jellel van, hanem 'IS NULL'-al. 

--Azon alkalmazottak teljes neve és részlegkódja kell, akik a 8-as vagy a 9-es 
--részlegen dolgoznak. Rendezés: részleg ID alapján csökkenő, azon belül 
--fizetés alapján növekvő sorba.
SELECT veznev, kernev, reszleg_id FROM alkalmazottak WHERE reszleg_id = 8 OR reszleg_id = 9 ORDER BY reszleg_id DESC, fizu;

--Listázd ki az 'Sh'-val kezdődő vezetékneveket. 
SELECT veznev FROM alkalmazottak WHERE veznev LIKE 'Sh%';
--Azon rekordok, ahol a vezetéknév 2. betűje az 'a'.
SELECT * FROM alkalmazottak WHERE veznev LIKE '_a%';
--Azon rekordok, ahol a keresztnév utolsó betűje az 'a'.
SELECT * FROM alkalmazottak WHERE veznev LIKE '%a';
